import{_ as t,o as s,c as a,ai as n}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Le nominatif","description":"","frontmatter":{},"headers":[],"relativePath":"module-2-construire-une-phrase/nominatif.md","filePath":"module-2-construire-une-phrase/nominatif.md","lastUpdated":1773233444000}'),i={name:"module-2-construire-une-phrase/nominatif.md"};function l(r,e,o,d,c,m){return s(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="le-nominatif" tabindex="-1">Le nominatif <a class="header-anchor" href="#le-nominatif" aria-label="Permalink to “Le nominatif”">​</a></h1><p><strong>Prérequis :</strong> <a href="./ordre-des-mots.html">L&#39;ordre des mots</a></p><p><strong>Objectif :</strong> comprendre ce qu&#39;est le nominatif, reconnaitre sa forme et savoir l&#39;utiliser.</p><p>Le nominatif est le premier des quatre cas de la langue allemande. C&#39;est le plus simple - il correspond au sujet de la phrase.</p><h2 id="qu-est-ce-qu-un-cas" tabindex="-1">Qu&#39;est-ce qu&#39;un cas ? <a class="header-anchor" href="#qu-est-ce-qu-un-cas" aria-label="Permalink to “Qu&#39;est-ce qu&#39;un cas ?”">​</a></h2><p>En allemand, les articles changent de forme selon la fonction du nom dans la phrase. Cette fonction s&#39;appelle un <strong>cas</strong>. Il y en a quatre : nominatif, accusatif, datif, genitif.</p><div class="info custom-block"><p class="custom-block-title">Pourquoi les cas existent</p><p>Les cas permettent de savoir qui fait quoi dans une phrase, meme si l&#39;ordre des mots change. C&#39;est ce qui rend l&#39;allemand plus flexible que le francais dans l&#39;ordre des mots.</p></div><h2 id="le-nominatif-le-sujet" tabindex="-1">Le nominatif : le sujet <a class="header-anchor" href="#le-nominatif-le-sujet" aria-label="Permalink to “Le nominatif : le sujet”">​</a></h2><p>Le nominatif est utilise pour le <strong>sujet de la phrase</strong> - celui ou ce qui fait l&#39;action.</p><p><em>Der Mann kauft ein Buch.</em> - <strong>L&#39;homme</strong> achete un livre. (der Mann = nominatif)</p><p><em>Die Frau schreibt einen Brief.</em> - <strong>La femme</strong> ecrit une lettre. (die Frau = nominatif)</p><h2 id="les-articles-au-nominatif" tabindex="-1">Les articles au nominatif <a class="header-anchor" href="#les-articles-au-nominatif" aria-label="Permalink to “Les articles au nominatif”">​</a></h2><div class="mt-6 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600"></th><th class="p-3 text-center font-semibold text-blue-700">Masculin (der)</th><th class="p-3 text-center font-semibold text-red-600">Feminin (die)</th><th class="p-3 text-center font-semibold text-green-700">Neutre (das)</th><th class="p-3 text-center font-semibold text-gray-700">Pluriel</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium text-gray-700">Article defini</td><td class="p-3 text-center font-bold text-blue-700">der</td><td class="p-3 text-center font-bold text-red-600">die</td><td class="p-3 text-center font-bold text-green-700">das</td><td class="p-3 text-center font-bold text-gray-700">die</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium text-gray-700">Article indefini</td><td class="p-3 text-center font-bold text-blue-700">ein</td><td class="p-3 text-center font-bold text-red-600">eine</td><td class="p-3 text-center font-bold text-green-700">ein</td><td class="p-3 text-center text-gray-400">-</td></tr></tbody></table></div><p>Au nominatif, les articles sont exactement ceux qu&#39;on a appris avec les genres : <em>der, die, das</em> et <em>ein, eine, ein</em>. Pas de changement ici.</p><h2 id="les-pronoms-personnels-au-nominatif" tabindex="-1">Les pronoms personnels au nominatif <a class="header-anchor" href="#les-pronoms-personnels-au-nominatif" aria-label="Permalink to “Les pronoms personnels au nominatif”">​</a></h2><p>Ce sont les pronoms sujets - les memes qu&#39;on utilise pour conjuguer les verbes.</p><div class="mt-4 grid grid-cols-2 gap-4"><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-gray-700 mb-3 text-sm uppercase tracking-wide">Singulier</div><div class="grid gap-2"><div class="flex justify-between"><span class="font-medium">ich</span><span class="text-gray-500">je</span></div><div class="flex justify-between"><span class="font-medium">du</span><span class="text-gray-500">tu</span></div><div class="flex justify-between"><span class="font-medium">er</span><span class="text-gray-500">il</span></div><div class="flex justify-between"><span class="font-medium">sie</span><span class="text-gray-500">elle</span></div><div class="flex justify-between"><span class="font-medium">es</span><span class="text-gray-500">il/elle (neutre)</span></div></div></div><div class="p-4 rounded-xl border border-gray-200"><div class="font-semibold text-gray-700 mb-3 text-sm uppercase tracking-wide">Pluriel</div><div class="grid gap-2"><div class="flex justify-between"><span class="font-medium">wir</span><span class="text-gray-500">nous</span></div><div class="flex justify-between"><span class="font-medium">ihr</span><span class="text-gray-500">vous (informel)</span></div><div class="flex justify-between"><span class="font-medium">sie</span><span class="text-gray-500">ils/elles</span></div><div class="flex justify-between"><span class="font-medium">Sie</span><span class="text-gray-500">vous (formel)</span></div></div></div></div><div class="warning custom-block"><p class="custom-block-title">sie, sie et Sie - trois pronoms, une orthographe</p><p><em>sie</em> (minuscule) = elle / <em>sie</em> (minuscule) = ils/elles / <em>Sie</em> (majuscule) = vous de politesse. Le contexte et la conjugaison permettent de les distinguer. <em>Sie</em> avec majuscule s&#39;ecrit toujours avec majuscule, meme en milieu de phrase.</p></div><h2 id="exemples-en-contexte" tabindex="-1">Exemples en contexte <a class="header-anchor" href="#exemples-en-contexte" aria-label="Permalink to “Exemples en contexte”">​</a></h2><ul><li><em>Der Hund ist groß.</em> - Le chien est grand. (<em>der Hund</em> = sujet, nominatif)</li><li><em>Eine Frau singt.</em> - Une femme chante. (<em>eine Frau</em> = sujet, nominatif)</li><li><em>Das Kind spielt.</em> - L&#39;enfant joue. (<em>das Kind</em> = sujet, nominatif)</li><li><em>Die Kinder spielen.</em> - Les enfants jouent. (<em>die Kinder</em> = sujet pluriel, nominatif)</li></ul><div class="tip custom-block"><p class="custom-block-title">A retenir</p><p>Le nominatif, c&#39;est la forme &quot;de base&quot; du nom - celle qu&#39;on trouve dans le dictionnaire. Quand un nom est sujet de la phrase, il est au nominatif et son article ne change pas.</p></div>',21)])])}const f=t(i,[["render",l]]);export{p as __pageData,f as default};
